previewCss:
.darma-loader-darma-custom-563 {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: var(--loader-secondary-color, #67e8f9);
  --loader-bg: var(--loader-bg, #ffffff);
   height: 6px;
   width: 60px;
   --c:no-repeat repeating-linear-gradient(90deg,currentColor 0 3px,#0000 0 6px);
   background: var(--c), var(--c);
   background-size: 100% 3px;
   animation: darma-loader-darma-custom-563-l9 1s infinite;
}
@keyframes darma-loader-darma-custom-563-l9  {
  0%, 70%, 100% {background-position: 0 50%,3px 50% }
23.33% {background-position: 0 0 ,3px 100%}
46.67% {background-position: 3px 0 ,0 100%}
69.99% {background-position: 3px 50%,0 50% }
}

